    // --- T003: Complete current step (delete one task) ---
    // Move cursor, highlight, then click delete on the chosen task
    await moveCursorTo(page, elTaskToDelete, 1000)
    await highlightElement(page, elTaskToDelete)
    await elTaskToDelete.click()

    // Wait for UI to settle after deletion
    await page.waitForTimeout(500)

    // --- T004: Click forward (no next step; verify task removed and count updated) ---
    // Verify the deleted task text is no longer visible
    const elDeletedTaskText = page.getByText('Design landing page').filter({ visible: true })
    await expect(elDeletedTaskText).toHaveCount(0)

    // Verify the remaining todos count is updated to be less than before
    const updatedCountText = await elRemainingCount.innerText()

    // Extract counts as numbers
    const initialMatch = initialCountText.match(/Your remaining todos : (\d+)/)
    const updatedMatch = updatedCountText.match(/Your remaining todos : (\d+)/)
    const initialCount = initialMatch ? parseInt(initialMatch[1], 10) : null
    const updatedCount = updatedMatch ? parseInt(updatedMatch[1], 10) : null

    // Assert updated count is one less than initial (if parsing succeeded)
    if (initialCount !== null && updatedCount !== null) {
      expect(updatedCount).toBe(initialCount - 1)
    }

    // Save final DOM snapshot
    await saveCurrentDom(page, testInfo)
  })
})

